import React from 'react';


function Header(props) {
    const { chatList, recipient, userData, contactPictures } = props;

    console.log(recipient);
    console.log(chatList);

    return (
        <div className="navbar">
            <div className="navbar-contact-container">
                {chatList && chatList.map((chat, index) => {
                    const otherUser = chat.chatParticipantsList.find(u => u.id !== userData.id);
                    return (
                        <button className="navbar-contacts-item">
                            <span className="current-person-icon">
                                <img
                                    className="sidebarContacts-picture"
                                    src={contactPictures[otherUser.id]}
                                ></img>
                                {otherUser.name}
                            </span>
                        </button>
                    );
                    }
                )}
            </div>

            <div className="voip-container">
                <button className="phone">
                    <i className="bi bi-telephone"></i>
                </button>
                <div className="voip-divider"></div>
                <button className="camera-video">
                    <i className="bi bi-camera-video"> </i>
                </button>
            </div>
        </div>

    );
}

export default Header;
